// Some portions generated by Codex

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.foreign.MemorySegment;
import java.util.List;

import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.CompactOmniSketch;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.OmniSketch;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.OmniSketchEstimate;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.OmniSketchPredicate;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.OmniSketches;
import org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni.UpdateOmniSketch;
import org.junit.jupiter.api.Test;

class OmniSketchCoreTest {

	@Test
	void zipOmniPackageIsVendored() {
		UpdateOmniSketch sketch = newSketch(16, 2, 16);

		assertEquals("OMNI", sketch.getFamily().getFamilyName());
	}

	@Test
	void pointInAndNullPredicatesFollowZipApi() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 1_000; i++) {
			sketch.update(i % 10, i);
		}
		for (int i = 1_000; i < 1_100; i++) {
			sketch.updateNull(i);
		}

		assertFalse(sketch.isEmpty());
		assertBetween(70.0d, 130.0d, sketch.getEstimate(3L));

		OmniSketchEstimate inEstimate = sketch.estimate(OmniSketchPredicate.anyOfLongs(1L, 2L));
		OmniSketchEstimate nullEstimate = sketch.estimate(OmniSketchPredicate.isNull());

		assertBetween(150.0d, 250.0d, inEstimate.getEstimate());
		assertBetween(80.0d, 120.0d, nullEstimate.getEstimate());
	}

	@Test
	void intersectionAcrossDimensionsFollowsZipApi() {
		UpdateOmniSketch country = newSketch(128, 4, 128);
		UpdateOmniSketch browser = newSketch(128, 4, 128);
		for (int user = 0; user < 2_000; user++) {
			country.update(user % 2 == 0 ? "NO" : "SE", user);
			browser.update(user % 4 == 0 ? "Firefox" : "Chrome", user);
		}

		OmniSketchEstimate estimate = OmniSketches.intersection(
				List.of(country, browser),
				List.of(OmniSketchPredicate.equalTo("NO"), OmniSketchPredicate.equalTo("Firefox")));

		assertBetween(400.0d, 600.0d, estimate.getEstimate());
	}

	@Test
	void compactSerializationHeapifiesAndWrapsZipImages() {
		UpdateOmniSketch sketch = newSketch(64, 3, 32);
		for (int i = 0; i < 300; i++) {
			sketch.update(i % 6, i);
		}
		CompactOmniSketch compact = sketch.compact();
		byte[] bytes = compact.toByteArray();
		assertEquals(bytes.length, compact.getCompactBytes());

		CompactOmniSketch heapified = OmniSketch.heapify(bytes);
		CompactOmniSketch wrapped = OmniSketch.wrap(MemorySegment.ofArray(bytes));

		assertEquals(sketch.getTotalUpdates(), heapified.getTotalUpdates());
		assertEquals(sketch.getEstimate(2L), heapified.getEstimate(2L));
		assertEquals(sketch.getEstimate(2L), wrapped.getEstimate(2L));
		assertTrue(wrapped.hasMemorySegment());
	}

	@Test
	void unionMergesPartitionsFollowingZipApi() {
		var builder = OmniSketch.builder().setWidth(64).setNumRows(3).setNominalEntries(64);
		UpdateOmniSketch left = builder.build();
		UpdateOmniSketch right = builder.build();
		for (int i = 0; i < 500; i++) {
			left.update(i % 5, i);
		}
		for (int i = 500; i < 1_000; i++) {
			right.update(i % 5, i);
		}

		var union = builder.buildUnion();
		union.update(left);
		union.update(right.compact());
		CompactOmniSketch result = union.getResult();

		assertEquals(1_000L, result.getTotalUpdates());
		assertBetween(150.0d, 250.0d, result.getEstimate(3L));
	}

	private static UpdateOmniSketch newSketch(int width, int rows, int nominalEntries) {
		return OmniSketch.builder()
				.setWidth(width)
				.setNumRows(rows)
				.setNominalEntries(nominalEntries)
				.build();
	}

	private static void assertBetween(double lowerExclusive, double upperExclusive, double value) {
		assertTrue(value > lowerExclusive, "estimate=" + value);
		assertTrue(value < upperExclusive, "estimate=" + value);
	}
}
